function addHeroLogo(){let t=document.getElementById("hero");if(!t)return;let e=document.createElement("div"),o=document.createElement("img");o.setAttribute("alt","Logo"),o.setAttribute("class","no-zoom"),o.setAttribute("src","https://pages.git.generalassemb.ly/modular-curriculum-all-courses/universal-resources-internal/static/v2/assets/hero-logo.png"),e.appendChild(o),document.getElementById("hero").prepend(e)}function addCodeBlockHighlighting(){hljs.highlightAll()}function attachFilePathsToCodeBlocks(){let t=document.querySelectorAll("p");t.forEach(function(t){t.nextElementSibling?.nodeName==="PRE"&&1===t.childNodes.length&&t.childNodes[0]?.nodeName==="CODE"&&(t.classList.add("collapse"),t.childNodes[0].classList.add("codeblock-filepath"))})}function addMediumZoom(){mediumZoom(document.querySelectorAll("main img:not(.no-zoom)"),{margin:24,background:null})}function setLinkAttrs(){let t=document.querySelectorAll("a");t.forEach(t=>{let e=t.getAttribute("href");e.startsWith("/")||t.setAttribute("target","_blank")})}function addAnchors(){anchors.add("h2:not(.no-anchor), h3:not(.no-anchor), h4:not(.no-anchor), h5:not(.no-anchor)")}document.addEventListener("DOMContentLoaded",function(t){addHeroLogo(),addCodeBlockHighlighting(),attachFilePathsToCodeBlocks(),setLinkAttrs(),addAnchors()});